tools.convertFn:
function convert(value, direction, extra) {
  if (direction === 'json2yaml') {
    try {
      var obj = JSON.parse(value);
      return toYaml(obj, 0);
    } catch(e) { return 'JSON解析错误: ' + e.message; }
  } else {
    try {
      var lines = value.split('\n');
      var obj = parseYaml(lines);
      return JSON.stringify(obj, null, 2);
    } catch(e) { return 'YAML解析错误: ' + e.message; }
  }
}
function toYaml(obj, indent) {
  var pad = '  '.repeat(indent);
  if (Array.isArray(obj)) {
    if (obj.length === 0) return '[]';
    return obj.map(function(item) { return pad + '- ' + (typeof item === 'object' ? '\n' + toYaml(item, indent+1) : JSON.stringify(item)); }).join('\n');
  }
  if (typeof obj === 'object' && obj !== null) {
    var keys = Object.keys(obj);
    if (keys.length === 0) return '{}';
    return keys.map(function(k) {
      var v = obj[k];
      if (typeof v === 'object' && v !== null) {
        return pad + k + ':\n' + toYaml(v, indent+1);
      }
      return pad + k + ': ' + (typeof v === 'string' ? v : JSON.stringify(v));
    }).join('\n');
  }
  return JSON.stringify(obj);
}
function parseYaml(lines) {
  var result = {}, stack = [{obj: result, indent: -1}];
  lines.forEach(function(line) {
    if (!line.trim() || line.trim().startsWith('#')) return;
    var indent = line.search(/\S/);
    var content = line.trim();
    var colonIdx = content.indexOf(':');
    if (colonIdx === -1) return;
    var key = content.slice(0, colonIdx).trim();
    var val = content.slice(colonIdx+1).trim();
    while (stack.length > 1 && stack[stack.length-1].indent >= indent) stack.pop();
    var current = stack[stack.length-1].obj;
    if (val === '' || val === '[]' || val === '{}') {
      current[key] = val === '[]' ? [] : (val === '{}' ? {} : undefined);
      if (Array.isArray(current[key]) || typeof current[key] === 'object') {
        stack.push({obj: current[key], indent: indent});
      }
    } else if (val === 'true' || val === 'false') {
      current[key] = val === 'true';
    } else if (!isNaN(val) && val !== '') {
      current[key] = Number(val);
    } else {
      current[key] = val.replace(/^['"]|['"]$/g, '');
    }
  });
  return result;
}

function convert(value, direction, extra) {
  if (direction === 'json2xml') {
    try {
      var obj = JSON.parse(value);
      return '<?xml version="1.0" encoding="UTF-8"?>\n' + jsonToXml(obj, 'root');
    } catch(e) { return 'JSON解析错误: ' + e.message; }
  } else {
    try {
      var parser = new DOMParser();
      var doc = parser.parseFromString(value, 'application/xml');
      if (doc.querySelector('parsererror')) return 'XML解析错误';
      var obj = xmlToJson(doc.documentElement);
      return JSON.stringify(obj, null, 2);
    } catch(e) { return 'XML解析错误: ' + e.message; }
  }
}
function jsonToXml(obj, tagName) {
  if (Array.isArray(obj)) {
    return obj.map(function(item) { return '<' + tagName + '>' + (typeof item === 'object' ? jsonToXml(item, 'item') : String(item)) + '</' + tagName + '>'; }).join('\n');
  }
  if (typeof obj === 'object' && obj !== null) {
    return Object.keys(obj).map(function(k) {
      return '<' + k + '>' + (typeof obj[k] === 'object' ? jsonToXml(obj[k], k) : String(obj[k])) + '</' + k + '>';
    }).join('\n');
  }
  return String(obj);
}
function xmlToJson(node) {
  var obj = {};
  if (node.attributes) {
    Array.from(node.attributes).forEach(function(attr) { obj['@' + attr.name] = attr.value; });
  }
  if (node.childNodes.length === 1 && node.childNodes[0].nodeType === 3) {
    var val = node.childNodes[0].nodeValue.trim();
    if (val) {
      if (!isNaN(val)) obj['#text'] = Number(val);
      else if (val === 'true' || val === 'false') obj['#text'] = val === 'true';
      else obj['#text'] = val;
    }
    return obj;
  }
  node.childNodes.forEach(function(child) {
    if (child.nodeType !== 1) return;
    var name = child.nodeName;
    var childObj = xmlToJson(child);
    if (obj[name]) {
      if (!Array.isArray(obj[name])) obj[name] = [obj[name]];
      obj[name].push(childObj);
    } else {
      obj[name] = childObj;
    }
  });
  return obj;
}

